ATTRIBUTE.VALUE:
Delete from WC_WRKFC_HEADCNT_F where SNAPSHOT_MONTH_WID
in (select distinct TO_number(TO_CHAR(SNAPSHOT_DATE,'YYYYMM'))  FROM PROD_BIDATA32.WC_WRKFC_HEADCNT_FS);
 
commit;

update W_EMPLOYEE_D set X_LEAVING_REASON=(select distinct term_reason from term_list_control ) ,x_actual_termination_dt=(select distinct actual_termination_date from term_list_control) where row_wid in (select f.employee_wid from WC_WRKFC_HEADCNT_F f,w_int_org_d d where f.X_GRE_WID=d.row_wid and f.snapshot_month_wid=201607 and d.org_name in ('CO-0251 FR Jacobs France','CO-0250 FR Jacobs Holding France') and f.x_active_flg=1) and x_actual_termination_dt is null;
commit;
update WC_WRKFC_HEADCNT_F set EVENT_TYPE_RSN_WID=(select row_wid from W_WRKFC_EVENT_TYPE_D where event_reason_code =(select distinct term_reason_code from term_list_control )),x_active_flg=0,x_terminated_flg=1,X_NEW_HIRE_FLG =0 where person_id in (select f.person_id from WC_WRKFC_HEADCNT_F f,w_int_org_d d where f.X_GRE_WID=d.row_wid and f.snapshot_month_wid=201607 and d.org_name in ('CO-0251 FR Jacobs France','CO-0250 FR Jacobs Holding France') and f.x_active_flg=1) and snapshot_month_wid=201607 ;
commit;
delete from WC_WRKFC_HEADCNT_F where person_id in (select f.person_id from WC_WRKFC_HEADCNT_F f,w_int_org_d d where f.X_GRE_WID=d.row_wid and f.snapshot_month_wid > 201607 and d.org_name in ('CO-0251 FR Jacobs France','CO-0250 FR Jacobs Holding France') ) and snapshot_month_wid > 201607 ; commit;

DELETE FROM WC_WRKFC_HEADCNT_FS WHERE PERSON_ID IN (SELECT PERSON_ID FROM WC_DVS_EMP_EXCLUSION_TMP
WHERE TRUNC(TO_DATE(W_INSERT_DT,'dd-mon-yy')) < TRUNC(TO_DATE('01-JUL-2024','dd-mon-yy')));

COMMIT;

DELETE FROM WC_EMP_HEAD_COUNT_DS WHERE PERSON_ID IN (SELECT PERSON_ID FROM WC_DVS_EMP_EXCLUSION_TMP
WHERE TRUNC(TO_DATE(W_INSERT_DT,'dd-mon-yy')) < TRUNC(TO_DATE('01-JUL-2024','dd-mon-yy')));

COMMIT;
